export default function Navbar() {
  const location = useLocation();
  const [navbarCollapsed, setNavbarCollapsed] = useState(true);
  const [navbarHeight, setNavbarHeight] = useState('0px');

  useEffect(() => {
    setNavbarCollapsed(true); // Collapse the navbar by default on each location change
  }, [location]);

  useEffect(() => {
    setNavbarHeight(navbarCollapsed ? '0px' : '100%');
  }, [navbarCollapsed]);

  const handleNavLinkClick = () => {
    setNavbarCollapsed(true); // Collapse the navbar when a navigation link is clicked
  };

  return (
    <>
      <div className="nav container-fluid">
        <header className="header1">
          <Link to="/" className="">
            <img className="triumphLogo ps-3 d-none d-md-flex" src={triumph} alt="tri" />
            <img className="triumphLogo3 ps-3 d-md-none p-0 m-0" src={triumph3} alt="tri" />
          </Link>
        </header>

        <nav className="navbar navbar-expand-lg bg-body-tertiary navcollapse">
          <div className="container-fluid d-flex justify-content-end">
            <button
              className="navbar-toggler"
              type="button"
              data-bs-toggle="collapse"
              data-bs-target="#navbarNav"
              aria-controls="navbarNav"
              aria-expanded={!navbarCollapsed ? 'true' : 'false'}
              aria-label="Toggle navigation"
              onClick={() => setNavbarCollapsed(!navbarCollapsed)}
            >
              <span className="navbar-toggler-icon"></span>
            </button>

            <div
              className={`collapse navbar-collapse ${navbarCollapsed ? '' : 'show'}`}
              style={{ maxHeight: navbarHeight, transition: 'max-height 0.3s ease-in-out' }}
              id="navbarNav"
            >
              <ul className="navbar-nav">
                <li className="nav-item">
                  <Link to="/" className="nav-link text-end " aria-current="page" href="#" onClick={handleNavLinkClick}>
                    Home
                  </Link>
                </li>

                <li className="nav-item">
                  <Link to="/leaders" className="nav-link text-end" onClick={handleNavLinkClick}>
                    Leaders
                  </Link>
                </li>

                <li className="nav-item">
                  <Link to="/contactUs" className="nav-link text-end " onClick={handleNavLinkClick}>
                    Contact Us
                  </Link>
                </li>

                <li className="nav-item">
                  <Link to="/give" className="nav-link text-end " onClick={handleNavLinkClick}>
                    Give
                  </Link>
                </li>
              </ul>
            </div>
          </div>
        </nav>
      </div>
    </>
  );
}
